    "code": "import { Overlay, OverlayModule, OverlayPositionBuilder, type OverlayRef } from '@angular/cdk/overlay';\nimport { TemplatePortal } from '@angular/cdk/portal';\nimport { isPlatformBrowser } from '@angular/common';\nimport {\n  booleanAttribute,\n  ChangeDetectionStrategy,\n  Component,\n  computed,\n  ElementRef,\n  inject,\n  input,\n  type OnDestroy,\n  output,\n  PLATFORM_ID,\n  signal,\n  type TemplateRef,\n  viewChild,\n  ViewContainerRef,\n  ViewEncapsulation,\n} from '@angular/core';\n\nimport type { ClassValue } from 'clsx';\n\nimport { ZardIdDirective } from '@/shared/core/directives/id.directive';\nimport { mergeClasses } from '@/shared/utils/merge-classes';\n\nimport { dropdownContentVariants } from './dropdown.variants';\n\n@Component({\n  selector: 'z-dropdown-menu',\n  imports: [OverlayModule, ZardIdDirective],\n  template: `\n    <!-- Dropdown Trigger -->\n    <div\n      #triggerContainer\n      zardId=\"dropdown-trigger\"\n      #zId=\"zardId\"\n      [id]=\"zId.id()\"\n      (click)=\"toggle()\"\n      (keydown.{enter,space}.prevent)=\"toggle()\"\n      tabindex=\"0\"\n    >\n      <ng-content select=\"[dropdown-trigger]\" />\n    </div>\n\n    <!-- Template for overlay content -->\n    <ng-template #dropdownTemplate>\n      <div\n        [class]=\"contentClasses()\"\n        role=\"menu\"\n        [attr.data-state]=\"'open'\"\n        (keydown.{arrowdown,arrowup,enter,space,escape,home,end}.prevent)=\"onDropdownKeydown($event)\"\n        tabindex=\"-1\"\n      >\n        <ng-content />\n      </div>\n    </ng-template>\n  `,\n  changeDetection: ChangeDetectionStrategy.OnPush,\n  encapsulation: ViewEncapsulation.None,\n  host: {\n    class: 'relative inline-block text-left',\n    '[attr.data-state]': 'isOpen() ? \"open\" : \"closed\"',\n    '(document:click)': 'onDocumentClick($event)',\n  },\n  exportAs: 'zDropdownMenu',\n})\nexport class ZardDropdownMenuComponent implements OnDestroy {\n  private elementRef = inject(ElementRef);\n  private overlay = inject(Overlay);\n  private overlayPositionBuilder = inject(OverlayPositionBuilder);\n  private viewContainerRef = inject(ViewContainerRef);\n  private platformId = inject(PLATFORM_ID);\n\n  readonly dropdownTemplate = viewChild.required<TemplateRef<unknown>>('dropdownTemplate');\n  readonly triggerContainer = viewChild.required<ElementRef<HTMLElement>>('triggerContainer');\n\n  private overlayRef?: OverlayRef;\n  private portal?: TemplatePortal;\n\n  readonly class = input<ClassValue>('');\n  readonly disabled = input(false, { transform: booleanAttribute });\n\n  readonly openChange = output<boolean>();\n\n  readonly isOpen = signal(false);\n  readonly focusedIndex = signal<number>(-1);\n\n  protected readonly contentClasses = computed(() => mergeClasses(dropdownContentVariants(), this.class()));\n\n  ngOnDestroy() {\n    this.destroyOverlay();\n  }\n\n  onDocumentClick(event: Event) {\n    if (!this.elementRef.nativeElement.contains(event.target as Node)) {\n      this.close();\n    }\n  }\n\n  onDropdownKeydown(e: Event) {\n    const items = this.getDropdownItems();\n    const { key } = e as KeyboardEvent;\n\n    switch (key) {\n      case 'ArrowDown':\n        this.navigateItems(1, items);\n        break;\n      case 'ArrowUp':\n        this.navigateItems(-1, items);\n        break;\n      case 'Enter':\n      case ' ':\n        this.selectFocusedItem(items);\n        break;\n      case 'Escape':\n        this.close();\n        this.focusTrigger();\n        break;\n      case 'Home':\n        this.focusFirstItem(items);\n        break;\n      case 'End':\n        this.focusLastItem(items);\n        break;\n    }\n  }\n\n  toggle() {\n    if (this.disabled()) {\n      return;\n    }\n    if (this.isOpen()) {\n      this.close();\n    } else {\n      this.open();\n    }\n  }\n\n  open() {\n    if (this.isOpen()) {\n      return;\n    }\n\n    if (!this.overlayRef) {\n      this.createOverlay();\n    }\n\n    if (!this.overlayRef) {\n      return;\n    }\n\n    this.portal = new TemplatePortal(this.dropdownTemplate(), this.viewContainerRef);\n    this.overlayRef.attach(this.portal);\n    this.isOpen.set(true);\n    this.openChange.emit(true);\n\n    setTimeout(() => {\n      this.focusDropdown();\n    }, 0);\n  }\n\n  close() {\n    if (this.overlayRef?.hasAttached()) {\n      this.overlayRef.detach();\n    }\n    this.isOpen.set(false);\n    this.focusedIndex.set(-1);\n    this.openChange.emit(false);\n  }\n\n  private createOverlay() {\n    if (this.overlayRef) {\n      return;\n    }\n\n    if (isPlatformBrowser(this.platformId)) {\n      try {\n        const positionStrategy = this.overlayPositionBuilder\n          .flexibleConnectedTo(this.elementRef)\n          .withPositions([\n            {\n              originX: 'start',\n              originY: 'bottom',\n              overlayX: 'start',\n              overlayY: 'top',\n              offsetY: 4,\n            },\n            {\n              originX: 'start',\n              originY: 'top',\n              overlayX: 'start',\n              overlayY: 'bottom',\n              offsetY: -4,\n            },\n          ])\n          .withPush(false);\n\n        this.overlayRef = this.overlay.create({\n          positionStrategy,\n          hasBackdrop: false,\n          scrollStrategy: this.overlay.scrollStrategies.reposition(),\n          minWidth: 200,\n          maxHeight: 400,\n        });\n      } catch (error) {\n        console.error('Error creating overlay:', error);\n      }\n    }\n  }\n\n  private destroyOverlay() {\n    if (this.overlayRef) {\n      this.overlayRef.dispose();\n      this.overlayRef = undefined;\n    }\n  }\n\n  private getDropdownItems(): HTMLElement[] {\n    if (!this.overlayRef?.hasAttached()) {\n      return [];\n    }\n    const dropdownElement = this.overlayRef.overlayElement;\n    return Array.from(\n      dropdownElement.querySelectorAll<HTMLElement>('z-dropdown-menu-item, [z-dropdown-menu-item]'),\n    ).filter(item => item.dataset['disabled'] === undefined);\n  }\n\n  private navigateItems(direction: number, items: HTMLElement[]) {\n    if (items.length === 0) {\n      return;\n    }\n\n    const currentIndex = this.focusedIndex();\n    let nextIndex: number;\n\n    if (currentIndex === -1) {\n      nextIndex = direction > 0 ? 0 : items.length - 1;\n    } else {\n      nextIndex = currentIndex + direction;\n      if (nextIndex < 0) {\n        nextIndex = items.length - 1;\n      } else if (nextIndex >= items.length) {\n        nextIndex = 0;\n      }\n    }\n\n    this.focusedIndex.set(nextIndex);\n    this.updateItemFocus(items, nextIndex);\n  }\n\n  private selectFocusedItem(items: HTMLElement[]) {\n    const currentIndex = this.focusedIndex();\n    if (currentIndex >= 0 && currentIndex < items.length) {\n      const item = items[currentIndex];\n      item.click();\n    }\n  }\n\n  private focusFirstItem(items: HTMLElement[]) {\n    if (items.length > 0) {\n      this.focusedIndex.set(0);\n      this.updateItemFocus(items, 0);\n    }\n  }\n\n  private focusLastItem(items: HTMLElement[]) {\n    if (items.length > 0) {\n      const lastIndex = items.length - 1;\n      this.focusedIndex.set(lastIndex);\n      this.updateItemFocus(items, lastIndex);\n    }\n  }\n\n  private updateItemFocus(items: HTMLElement[], focusedIndex: number) {\n    items.forEach((item, index) => {\n      if (index === focusedIndex) {\n        item.focus();\n        item.setAttribute('data-highlighted', '');\n      } else {\n        item.removeAttribute('data-highlighted');\n      }\n    });\n  }\n\n  private focusDropdown() {\n    if (this.overlayRef?.hasAttached()) {\n      const dropdownElement = this.overlayRef.overlayElement.querySelector('[role=\"menu\"]') as HTMLElement;\n      if (dropdownElement) {\n        dropdownElement.focus();\n      }\n    }\n  }\n\n  private focusTrigger() {\n    this.triggerContainer().nativeElement.focus();\n  }\n}\n",
